package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Constructor;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class LinkedTreeMapTest {

  LinkedTreeMap<String, String> map;

  @BeforeEach
  void setUp() {
    map = new LinkedTreeMap<>();
  }

  @Test
  void containsKey_existingKey_returnsTrue() {
    map.put("key1", "value1");
    assertTrue(map.containsKey("key1"));
  }

  @Test
  void containsKey_nonExistingKey_returnsFalse() {
    map.put("key1", "value1");
    assertFalse(map.containsKey("key2"));
  }

  @Test
  void containsKey_nullKeyWhenAllowed_returnsTrue() throws Exception {
    // Create instance with allowNullValues = true via reflection constructor
    Constructor<LinkedTreeMap> constructor = LinkedTreeMap.class.getDeclaredConstructor(boolean.class);
    constructor.setAccessible(true);
    @SuppressWarnings("unchecked")
    LinkedTreeMap<String, String> mapAllowNull = constructor.newInstance(true);

    mapAllowNull.put(null, "nullValue");
    assertTrue(mapAllowNull.containsKey(null));
  }

  @Test
  void containsKey_nullKeyWhenNotAllowed_returnsFalse() {
    assertFalse(map.containsKey(null));
  }

  @Test
  void containsKey_callsFindByObjectUsingReflection() throws Exception {
    map.put("key1", "value1");

    Method findByObject = LinkedTreeMap.class.getDeclaredMethod("findByObject", Object.class);
    findByObject.setAccessible(true);

    Object node = findByObject.invoke(map, "key1");
    assertNotNull(node);

    Object nodeNull = findByObject.invoke(map, "nonexistent");
    assertNull(nodeNull);
  }
}
